#!/usr/bin/env node
// Generates `index.page.tsx` listing pages for every folder under
// src/pages/tests that does not already have one. Existing index.page.tsx
// files are left untouched unless they were generated by this script (they
// may be real test pages, not listings).
//
// Run from the `examples/` package root:
//   node scripts/generate-index-pages.js

const fs = require('fs');
const path = require('path');

const EXAMPLES_ROOT = path.resolve(__dirname, '..');
const TESTS_PAGES_DIR = path.join(EXAMPLES_ROOT, 'src', 'pages', 'tests');
const PAGE_SUFFIX = '.page.tsx';
const INDEX_FILE = `index${PAGE_SUFFIX}`;

const isExcludedFolder = (name) =>
  name.startsWith('.') ||
  name.startsWith('_') ||
  name === 'node_modules' ||
  name.endsWith('-snapshots');

const buildIndexFileContents = () => {
  return `import { TestPagesIndex } from '@examples/test-index/TestPagesIndex';
import { buildTestPagesIndexProps } from '@examples/test-index/buildTestPagesIndexProps';

export const getStaticProps = async () => ({ props: buildTestPagesIndexProps(__filename) });
export default TestPagesIndex;
`;
};

const walk = (dir) => {
  const entries = fs.readdirSync(dir, { withFileTypes: true });

  const indexPath = path.join(dir, INDEX_FILE);
  if (!fs.existsSync(indexPath)) {
    fs.writeFileSync(indexPath, buildIndexFileContents());
    console.log(`created ${path.relative(EXAMPLES_ROOT, indexPath)}`);
  } else {
    const existing = fs.readFileSync(indexPath, 'utf8');
    // only overwrite our own generated index pages — leave anything else alone
    const isGenerated =
      existing.includes("from '@examples/test-index/TestPagesIndex'") ||
      existing.includes("from '@examples/test-index/buildTestPagesIndexProps'");
    if (isGenerated) {
      const next = buildIndexFileContents();
      if (existing !== next) {
        fs.writeFileSync(indexPath, next);
        console.log(`updated ${path.relative(EXAMPLES_ROOT, indexPath)}`);
      } else {
        console.log(`unchanged ${path.relative(EXAMPLES_ROOT, indexPath)}`);
      }
    } else {
      console.log(
        `skipped ${path.relative(EXAMPLES_ROOT, indexPath)} (custom page)`,
      );
    }
  }

  for (const entry of entries) {
    if (entry.isDirectory() && !isExcludedFolder(entry.name)) {
      walk(path.join(dir, entry.name));
    }
  }
};

walk(TESTS_PAGES_DIR);
